using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve compat with existing documents that use "Discriminator".
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change #2: Id property now maps to "id" in JSON (was "Id").
        // Existing documents store the EF-synthesized id as "id" already, but the
        // *shadow __id* property carried the CLR value. Explicitly map to keep reads working.
        modelBuilder.Entity<Blog>().Property(b => b.Id).ToJsonProperty("Id");

        // Breaking change #3: EF 9 no longer synthesizes id as "EntityType|KeyValue".
        // Existing documents have id = "Blog|1". Tell EF to keep using that format.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);

        // Breaking change #4: Cosmos DB provider does not support indexes (HasIndex).
        // Removed the HasIndex call — indexes are managed in Cosmos directly.
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change #5: Sync I/O now throws by default in EF 9.
        // If sync calls (ToList, SaveChanges) are required, opt in explicitly.
        // Prefer migrating to async (ToListAsync / SaveChangesAsync) long-term.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

