 using Microsoft.EntityFrameworkCore;
 class SyncJob
 {
     // Breaking change #5 fix: EF 9 Cosmos provider throws on sync I/O by default.
     // Migrated to async. If sync is absolutely required, call
     //   context.Database.AutoTransactionBehavior  — or better yet, set
     //   CosmosOptionsExtension EnableSyncExecution (not public; async is the fix).
     async Task RunAsync(BlogContext context)
     {
         var blogs = await context.Blogs.ToListAsync();
         foreach (var b in blogs) { b.Name = b.Name.Trim(); }
         await context.SaveChangesAsync();
     }
 }

